proof_block:
// The synthetic ensures has shape `(H) ==> det_push_equal(...)` where H is
// the conjunction of `push`'s ensures evaluated on both runs. H is the
// HYPOTHESIS of the implication, so it is NOT a free fact at the top of the
// body — which is exactly why the previous attempt's bare top-level
// `assert(post1_self_@ == pre_self_@.push(*new_value))` and friends failed,
// and why the `recommends self.wf()` of `get_node_ref` went unmet.
//
// Introduce H into scope by guarding the proof with a proof-mode `if` on the
// full antecedent: under the branch every conjunct of H is a hypothesis on
// the path condition, so each component of `det_push_equal` can be
// discharged with proper preconditions in scope. On the else path the
// antecedent is false, so the implication ensures holds vacuously.
if ({
    &&& post1_self_.wf()
    &&& post1_self_@ == pre_self_@.push(*new_value)
    &&& post1_self_.len() == pre_self_.len() + 1
    &&& (forall|v: T|
            #![auto]
            pre_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v))
    &&& post1_self_.get_node_ref(*new_value) == r1
    &&& post1_self_.unique()
    &&& post2_self_.wf()
    &&& post2_self_@ == pre_self_@.push(*new_value)
    &&& post2_self_.len() == pre_self_.len() + 1
    &&& (forall|v: T|
            #![auto]
            pre_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v))
    &&& post2_self_.get_node_ref(*new_value) == r2
    &&& post2_self_.unique()
}) {
    // Both post views collapse to `pre_self_@.push(*new_value)`, so by Seq
    // extensionality their `.view()`s coincide — this discharges the
    // `view() == view()` conjunct of det_push_equal.
    lemma_push_view_eq::<T, N>(pre_self_, *new_value, post1_self_, post2_self_);
    assert(post1_self_@ == pre_self_@.push(*new_value));
    assert(post2_self_@ == pre_self_@.push(*new_value));
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_.view() == post2_self_.view());

    // Combine the two `forall|v| pre@.contains(v) ==> pre.get_node_ref(v)
    // == postN.get_node_ref(v)` ensures pointwise through a single explicit
    // shared trigger — this is the trigger gap z3 missed.
    lemma_push_get_node_ref_preserved::<T, N>(pre_self_, post1_self_, post2_self_);
    assert forall|v: T|
        #![trigger post1_self_.get_node_ref(v), post2_self_.get_node_ref(v)]
        pre_self_@.contains(v)
        implies post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v)
    by {
        assert(pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
        assert(pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));
    }

    // Surface `get_node_ref(*new_value)` on both runs as explicit
    // sub-expressions; with `post*_self_.wf()` in scope the `recommends
    // self.wf()` for get_node_ref is met, so z3 can connect r1/r2 to the
    // closed-spec `get_node_ref` symbol on both runs.
    assert(post1_self_.get_node_ref(*new_value) == r1);
    assert(post2_self_.get_node_ref(*new_value) == r2);

    // Pull `no_duplicates` of the spec_seq on both posts via the only
    // exposed structural lemma for StaticLinkedList; combined with the
    // shared view this gives z3 the per-element positional facts it
    // needs to align `get_node_ref` on the new value across both runs.
    post1_self_.wf_to_no_duplicates();
    post2_self_.wf_to_no_duplicates();
    assert(post1_self_.spec_seq@.no_duplicates());
    assert(post2_self_.spec_seq@.no_duplicates());
    assert(post1_self_.spec_seq@ == post2_self_.spec_seq@);
}

helper_lemmas:
proof fn lemma_push_view_eq<T: Copy, const N: usize>(
    pre: StaticLinkedList<T, N>,
    new_value: T,
    post1: StaticLinkedList<T, N>,
    post2: StaticLinkedList<T, N>,
)
    requires
        post1@ == pre@.push(new_value),
        post2@ == pre@.push(new_value),
    ensures
        post1.view() == post2.view(),
        post1@ == post2@,
{
    assert(post1@ =~= post2@);
    assert(post1.view() =~= post2.view());
}

proof fn lemma_push_get_node_ref_preserved<T: Copy, const N: usize>(
    pre: StaticLinkedList<T, N>,
    post1: StaticLinkedList<T, N>,
    post2: StaticLinkedList<T, N>,
)
    requires
        forall|v: T|
            #![auto]
            pre@.contains(v) ==> pre.get_node_ref(v) == post1.get_node_ref(v),
        forall|v: T|
            #![auto]
            pre@.contains(v) ==> pre.get_node_ref(v) == post2.get_node_ref(v),
    ensures
        forall|v: T|
            #![trigger post1.get_node_ref(v), post2.get_node_ref(v)]
            pre@.contains(v) ==> post1.get_node_ref(v) == post2.get_node_ref(v),
{
    assert forall|v: T|
        #![trigger post1.get_node_ref(v), post2.get_node_ref(v)]
        pre@.contains(v) implies post1.get_node_ref(v) == post2.get_node_ref(v)
    by {
        assert(pre.get_node_ref(v) == post1.get_node_ref(v));
        assert(pre.get_node_ref(v) == post2.get_node_ref(v));
    }
}
